name: Approve Workflows

on:
  pull_request_target:
    types:
      - labeled
      - synchronize
    branches:
      - main
      - 'release-**'

concurrency:
  group: ${{ github.workflow }}-${{ github.event.pull_request.number }}
  cancel-in-progress: false

jobs:
  approve:
    name: Approve Workflow Runs
    runs-on: ubuntu-latest
    if: >
      github.event.pull_request.author_association != 'FIRST_TIME_CONTRIBUTOR' ||
      contains(github.event.pull_request.labels.*.name, 'ok-to-test')
    steps:
      - name: Approve pending workflow runs
        uses: actions/github-script@v7
        with:
          script: |
            const owner = context.repo.owner;
            const repo = context.repo.repo;
            const prNumber = context.payload.pull_request.number;
            const headSha = context.payload.pull_request.head.sha;

            // Check if contributor has previous PRs
            const contributor = context.payload.pull_request.user.login;
            const hasOkToTest = context.payload.pull_request.labels.some(
              l => l.name === 'ok-to-test'
            );

            if (!hasOkToTest) {
              // Check if contributor is a repeat contributor
              const { data: prs } = await github.rest.pulls.list({
                owner,
                repo,
                author: contributor,
                state: 'closed',
              });

              if (prs.length < 2) {
                console.log(`Contributor ${contributor} is first-time. Skipping approval.`);
                return;
              }
            }

            // List workflow runs for the head SHA with action_required status
            const { data: runs } = await github.rest.actions.listWorkflowRunsForBranch({
              owner,
              repo,
              branch: context.payload.pull_request.head.ref,
              head_sha: headSha,
              status: 'action_required',
              per_page: 50,
            });

            for (const run of runs.workflow_runs || []) {
              await github.rest.actions.approveWorkflowRun({
                owner,
                repo,
                run_id: run.id,
              });
              console.log(`Approved workflow run: ${run.name} (${run.id})`);
            }

            console.log(`Processed ${runs.workflow_runs?.length || 0} pending workflow runs.`);

